/**
 * MedX labels accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Accessible name computation for controls.
 */
const LABELS_TOKENS = Object.freeze({
  primary: { value: "a11y-labels-primary", scope: "a11y" },
  secondary: { value: "a11y-labels-secondary", scope: "a11y" },
  muted: { value: "a11y-labels-muted", scope: "a11y" },
  accent: { value: "a11y-labels-accent", scope: "a11y" },
  surface: { value: "a11y-labels-surface", scope: "a11y" },
});

const LABELS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const LABELS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const labelsRegistry = new Map();
const LABELS_listeners = new Set();
let LABELS_seq = 0;

function createLabelsId(prefix = "medx-a11y-labels") {
  LABELS_seq += 1;
  return `${prefix}-${LABELS_seq}`;
}

function registerLabels(config = {}) {
  const entryId = config.id ?? createLabelsId();
  const preset = LABELS_PRESETS[config.preset ?? "default"] ?? LABELS_PRESETS.default;
  const token = LABELS_TOKENS[config.token ?? preset.token] ?? LABELS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: LABELS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  labelsRegistry.set(entryId, entry);
  notifyLabelsListeners("register", entry);
  return entry;
}

function updateLabels(id, patch = {}) {
  const entry = labelsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyLabelsListeners("update", entry);
  return entry;
}

function resolveLabels(id) {
  const entry = labelsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listLabelsEntries(filter = {}) {
  let items = Array.from(labelsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onLabelsEvent(listener) {
  LABELS_listeners.add(listener);
  return () => LABELS_listeners.delete(listener);
}

function notifyLabelsListeners(type, entry) {
  for (const listener of LABELS_listeners) {
    try {
      listener({ type, entry, registrySize: labelsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:labels] listener error", err.message);
    }
  }
}

function getLabelsMetrics() {
  const items = listLabelsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(LABELS_TOKENS).length,
    presets: Object.keys(LABELS_PRESETS).length,
  };
}

async function runMedxLabels() {
  console.log("[medx:ui:a11y:labels] runtime initialized");
  console.log(`[medx:ui:a11y:labels] tokens=${Object.keys(LABELS_TOKENS).length} presets=${Object.keys(LABELS_PRESETS).length}`);

  const events = [];
  onLabelsEvent((e) => events.push(e.type));

  const domains = Object.keys(LABELS_SUPPLY_CHAIN);
  const presets = Object.keys(LABELS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerLabels({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/labels" },
    });
  }

  const first = listLabelsEntries()[0];
  if (first) updateLabels(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getLabelsMetrics();
  const resolved = first ? resolveLabels(first.id) : null;

  console.log(`[medx:ui:a11y:labels] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:labels] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:labels] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:labels] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:labels] bootstrap complete");
}

module.exports = runMedxLabels;
